/**온라인 민원 게시판 리스트*/
SELECT A.* FROM (

SELECT A.*
FROM t_inqry A
WHERE 1 =1

ORDER BY IDX DESC

) A
limit #{firstRecordIndex},#{recordCountPerPage}

