/** 온라인 민원 게시판 수정 */ UPDATE t_inqry
ANSWER= #{answer}, STATUS= #{status},
TITLE = #{title}, CONTENT= #{content}, PASSWORD=#{password}, CONTACT=#{contact}, EMAIL=#{email}, REG_NM=#{regNm}, REG_NK=#{regNk},
MOD_DTIME=#{modDtime}
WHERE IDX=#{idx}

/** 온라인 민원 게시판 상태값 수정 */
